@Test public void handlesAbsPrefixWithEmptyBaseUri() {
    Document doc = Jsoup.parse("<a href='relative/path'>Link</a>");
    Element a = doc.select("a").first();
    assertFalse(a.hasAttr("abs:href"));
    assertTrue(a.hasAttr("href"));
    assertEquals("", a.absUrl("href"));
}

@Test public void handlesAbsPrefixWithFullUrl() {
    Document doc = Jsoup.parse("<img src='https://example.com/image.png'>", "http://jsoup.org/");
    Element img = doc.select("img").first();
    assertTrue(img.hasAttr("abs:src"));
    assertEquals("https://example.com/image.png", img.attr("abs:src"));
}

@Test public void handlesAbsPrefixWithMissingAttr() {
    Document doc = Jsoup.parse("<a>No href</a>", "http://jsoup.org/");
    Element a = doc.select("a").first();
    assertFalse(a.hasAttr("abs:href"));
    assertFalse(a.hasAttr("href"));
}
